@namespace sv_de882de1289a4dd292ccd0f8d10af5fb.Components.FileDropZone
@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (_entries.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _entries)
        {
            <li class="file-entry @(entry.Error is not null ? "file-error" : "")">
                @if (entry.Error is not null)
                {
                    <span class="error-message">@entry.Info.Name &mdash; @entry.Error</span>
                }
                else
                {
                    <span class="file-name">@entry.Info.Name</span>
                    <span class="file-size">@FormatSize(entry.Info.Size)</span>
                    <span class="file-type">@entry.Info.Type</span>
                }
                <button class="btn-remove" @onclick="() => Remove(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxSizeBytes = 10 * 1024 * 1024; // 10 MB

    [Parameter] public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _selfRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _entries = new();

    private record FileEntry(FileInfo Info, string? Error);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _module = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./_content/sv-de882de1289a4dd292ccd0f8d10af5fb/Components/FileDropZone/FileDropZone.razor.js");
        _selfRef = DotNetObjectReference.Create(this);
        await _module.InvokeVoidAsync("init", _dropZoneRef, _selfRef);
    }

    [JSInvokable]
    public void OnDragOverChanged(bool isOver)
    {
        _isDragOver = isOver;
        InvokeAsync(StateHasChanged);
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileInfo[] files)
    {
        _isDragOver = false;

        foreach (var file in files)
        {
            var error = file.Size > MaxSizeBytes
                ? $"File exceeds 10 MB limit ({FormatSize(file.Size)})"
                : null;
            _entries.Add(new FileEntry(file, error));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task Remove(FileEntry entry)
    {
        _entries.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _entries
            .Where(e => e.Error is null)
            .Select(e => e.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try { await _module.InvokeVoidAsync("dispose", _dropZoneRef); } catch { }
            await _module.DisposeAsync();
        }
        _selfRef?.Dispose();
    }
}

.drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    color: #6c757d;
    font-size: 1rem;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-name {
    font-weight: 600;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.875rem;
}

.error-message {
    color: #dc3545;
    flex: 1;
}

.btn-remove {
    margin-left: auto;
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.2rem 0.5rem;
    cursor: pointer;
    font-size: 0.8rem;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

const handlers = new Map();

export function init(element, dotNetRef) {
    const onDragOver = (e) => {
        e.preventDefault();
        dotNetRef.invokeMethodAsync('OnDragOverChanged', true);
    };

    const onDragLeave = (e) => {
        // Only fire when leaving the drop zone itself, not child elements
        if (!element.contains(e.relatedTarget)) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    };

    const onDrop = (e) => {
        e.preventDefault();
        const files = Array.from(e.dataTransfer.files).map(f => ({
            name: f.name,
            size: f.size,
            type: f.type || 'application/octet-stream'
        }));
        if (files.length > 0) {
            dotNetRef.invokeMethodAsync('OnFilesDropped', files);
        } else {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    };

    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    handlers.set(element, { onDragOver, onDragLeave, onDrop });
}

export function dispose(element) {
    const h = handlers.get(element);
    if (h) {
        element.removeEventListener('dragover', h.onDragOver);
        element.removeEventListener('dragleave', h.onDragLeave);
        element.removeEventListener('drop', h.onDrop);
        handlers.delete(element);
    }
}

