    {
        _isDragOver = isOver;
        InvokeAsync(StateHasChanged);
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileInfo[] files)
    {
        _isDragOver = false;

        foreach (var file in files)
        {
            var error = file.Size > MaxSizeBytes
